--- /dev/null
+++ b/pkg/crdt/convergence_test.go
@@ -0,0 +1,29 @@
+package crdt
+
+import "testing"
+
+// Removal observed on one replica must survive a later merge from a replica
+// that still holds the element.
+func TestORSet_RemovePersistsAfterMerge(t *testing.T) {
+	a := NewORSet()
+	a.Add("x", "n1")
+
+	b := NewORSet()
+	b.Merge(a) // b observes the add
+	b.Remove("x")
+
+	a.Merge(b) // a merges b's removal
+	if a.Contains("x") {
+		t.Fatal("removal must persist after merge")
+	}
+}
+
+// ORMap deletes must not be resurrected by a later merge.
+func TestORMap_DeletePersistsAfterMerge(t *testing.T) {
+	a := NewORMap()
+	a.Put("k", "v", 100, "n1")
+
+	b := NewORMap()
+	b.Merge(a)
+	b.Delete("k")
+
+	a.Merge(b)
+	if _, ok := a.Get("k"); ok {
+		t.Fatal("delete must persist after merge")
+	}
+}

