diff --git a/pkg/crdt/convergence_test.go b/pkg/crdt/convergence_test.go
new file mode 100644
--- /dev/null
+++ b/pkg/crdt/convergence_test.go
@@ -0,0 +1,140 @@
+package crdt
+
+import "testing"
+
+// A removal observed on one replica must never be undone by a later merge
+// from a replica that still holds the element.
+func TestORSet_RemoveStaysRemovedAfterMerge(t *testing.T) {
+	a := NewORSet()
+	a.Add("x", "n1")
+
+	b := NewORSet()
+	b.Merge(a) // b observes x
+
+	a.Remove("x") // a removes x
+	b.Merge(a)    // merging a's removal must drop x from b
+
+	if b.Contains("x") {
+		t.Fatal("removed element resurrected after merge")
+	}
+}
+
+// Convergence must hold regardless of merge order or repetition.
+func TestORSet_ConvergesUnderReorderedMerges(t *testing.T) {
+	build := func() (*ORSet, *ORSet, *ORSet) {
+		a := NewORSet()
+		b := NewORSet()
+		c := NewORSet()
+		a.Add("k", "n1")
+		b.Merge(a)
+		c.Merge(a)
+		b.Remove("k") // b removes after observing the add
+		return a, b, c
+	}
+
+	// Order 1: a<-b<-c, b<-c<-a, c<-a<-b
+	a1, b1, c1 := build()
+	a1.Merge(b1)
+	a1.Merge(c1)
+	b1.Merge(c1)
+	b1.Merge(a1)
+	c1.Merge(a1)
+	c1.Merge(b1)
+	// Repeat merges (idempotency)
+	a1.Merge(b1)
+	a1.Merge(c1)
+
+	if a1.Contains("k") || b1.Contains("k") || c1.Contains("k") {
+		t.Fatalf("replicas disagree: a=%v b=%v c=%v",
+			a1.Contains("k"), b1.Contains("k"), c1.Contains("k"))
+	}
+}
+
+// Add-wins: a concurrent add carrying a tag the remover never observed survives.
+func TestORSet_ConcurrentAddWinsAcrossMerges(t *testing.T) {
+	a := NewORSet()
+	a.Add("x", "n1")
+
+	b := NewORSet()
+	b.Merge(a)
+	b.Remove("x") // b removes the observed tag
+
+	a.Add("x", "n1") // concurrent re-add with a fresh, unseen tag
+
+	a.Merge(b)
+	b.Merge(a)
+
+	if !a.Contains("x") || !b.Contains("x") {
+		t.Fatalf("concurrent add should win: a=%v b=%v",
+			a.Contains("x"), b.Contains("x"))
+	}
+}
+
+// ORMap: deleted keys must not be resurrected by a later merge.
+func TestORMap_DeleteStaysDeletedAfterMerge(t *testing.T) {
+	a := NewORMap()
+	a.Put("k", "v", 100, "n1")
+
+	b := NewORMap()
+	b.Merge(a) // b observes k
+
+	a.Delete("k")
+	b.Merge(a)
+
+	if _, ok := b.Get("k"); ok {
+		t.Fatal("deleted key resurrected after merge")
+	}
+}
+
+// ORMap: last-writer-wins value resolution survives merges in any order.
+func TestORMap_LWWValueResolutionAfterMerge(t *testing.T) {
+	a := NewORMap()
+	a.Put("k", "old", 100, "n1")
+
+	b := NewORMap()
+	b.Put("k", "new", 200, "n2")
+
+	a.Merge(b)
+	b.Merge(a)
+
+	va, oka := a.Get("k")
+	vb, okb := b.Get("k")
+	if !oka || !okb {
+		t.Fatal("key should be present on both replicas")
+	}
+	if va != "new" || vb != "new" {
+		t.Fatalf("LWW mismatch: a=%v b=%v", va, vb)
+	}
+}
+
+// ORMap: a concurrent put after a delete (add-wins) must survive, keeping its value.
+func TestORMap_ConcurrentPutWinsOverDelete(t *testing.T) {
+	a := NewORMap()
+	a.Put("k", "v1", 100, "n1")
+
+	b := NewORMap()
+	b.Merge(a)
+	b.Delete("k")
+
+	a.Put("k", "v2", 200, "n1") // concurrent re-put, fresh tag
+
+	a.Merge(b)
+	b.Merge(a)
+
+	va, oka := a.Get("k")
+	vb, okb := b.Get("k")
+	if !oka || !okb {
+		t.Fatalf("concurrent put should win: a=%v b=%v", oka, okb)
+	}
+	if va != "v2" || vb != "v2" {
+		t.Fatalf("expected v2 on both, got a=%v b=%v", va, vb)
+	}
+}
